from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    def clean_object(obj):
        """Remove quotes from string values"""
        if obj.startswith('"') and obj.endswith('"'):
            return obj[1:-1]
        return obj

    def get_phrase(predicate, obj, subject):
        """Convert predicate to natural language phrase"""
        obj = clean_object(obj)

        if predicate == "alternativeName":
            return f"also known as {obj}"
        elif predicate == "creator":
            return f"created by {obj}"
        elif predicate == "fullName":
            return f"whose full name is {obj}"
        elif predicate == "foundedBy":
            return f"founded by {obj}"
        elif predicate == "keyPerson":
            return f"key person is {obj}"
        elif predicate == "city":
            return f"based in {obj}"
        elif predicate == "product":
            return f"produces {obj}"
        elif predicate == "lastAired":
            return f"last aired on {obj}"
        elif predicate == "starring":
            return f"starring {obj}"
        elif predicate == "firstAppearanceInFilm":
            return f"first appeared in the film {obj}"
        elif predicate == "voice":
            return f"voiced by {obj}"
        elif predicate == "distributor":
            return f"distributed by {obj}"
        elif predicate == "birthPlace":
            return f"born in {obj}"
        elif predicate == "nationality":
            # Handle nationality more naturally - convert to adjective form
            if obj == "Americans":
                return "American"
            elif obj == "United States":
                return "American"
            elif obj.endswith("s"):
                return obj[:-1]
            else:
                return obj
        elif predicate == "award":
            return f"received the {obj}"
        elif predicate == "broadcastedBy":
            return f"broadcasted by {obj}"
        elif predicate == "firstAired":
            return f"first aired on {obj}"
        elif predicate == "series":
            return f"part of the series {obj}"
        elif predicate == "child":
            return f"has a child named {obj}"
        return None

    def clean_subject(subj):
        """Clean subject name by removing common suffixes"""
        if "(comicsCharacter)" in subj:
            return subj.replace(" (comicsCharacter)", "").replace("(comicsCharacter)", "")
        return subj

    # Group triples by subject and predicate for complex sentence building
    subject_triples = {}
    predicate_objects = {}  # Group objects by predicate for same subject
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
            predicate_objects[t.subject] = {}
        subject_triples[t.subject].append(t)

        # Group objects by predicate for combining multiple values
        if t.predicate not in predicate_objects[t.subject]:
            predicate_objects[t.subject][t.predicate] = []
        predicate_objects[t.subject][t.predicate].append(t.object)

    # Build ONE complex sentence from all triples
    all_clauses = []
    subjects = list(subject_triples.keys())

    for idx, subject in enumerate(subjects):
        # Clean subject name
        clean_subj = clean_subject(subject)

        subject_trips = subject_triples[subject]

        # Sort triples by priority (more important info first)
        priority = ["creator", "fullName", "alternativeName", "nationality", "birthPlace", "award", "child", "series", "city", "product", "starring", "voice", "distributor", "firstAppearanceInFilm", "firstAired", "lastAired", "broadcastedBy", "foundedBy", "keyPerson", "birthPlace", "nationality"]
        sorted_trips = sorted(subject_trips, key=lambda t: priority.index(t.predicate) if t.predicate in priority else len(priority))

        # Group objects by predicate to handle multiple values (e.g., multiple creators)
        predicate_grouped = {}
        for t in sorted_trips:
            if t.predicate not in predicate_grouped:
                predicate_grouped[t.predicate] = []
            predicate_grouped[t.predicate].append(t.object)

        # Build clauses for this subject
        subject_clauses = []

        for i, (pred, objects) in enumerate(predicate_grouped.items()):
            # Handle multiple objects for same predicate
            if len(objects) == 1:
                obj = objects[0]
                phrase = get_phrase(pred, obj, subject)
            else:
                # Join multiple objects with "and"
                obj_str = " and ".join(objects)
                phrase = get_phrase(pred, obj_str, subject)

            if phrase:
                if i == 0:
                    # First clause - make it the main clause
                    if pred == "nationality":
                        subject_clauses.append(f"{clean_subj} is {phrase}")
                    elif pred == "creator":
                        subject_clauses.append(f"{clean_subj}, {phrase}")
                    else:
                        subject_clauses.append(f"{clean_subj}, {phrase}")
                else:
                    # Subsequent clauses - use relative clauses
                    if pred == "alternativeName":
                        subject_clauses.append(f" {phrase}")
                    elif pred == "nationality":
                        subject_clauses.append(f", and is {phrase}")
                    else:
                        subject_clauses.append(f", {phrase}")

        if subject_clauses:
            all_clauses.append("".join(subject_clauses))

    # Combine all subject clauses into one complex sentence
    if len(all_clauses) == 0:
        return ""
    elif len(all_clauses) == 1:
        return all_clauses[0] + "."
    else:
        # Connect multiple subjects with appropriate conjunctions
        result = all_clauses[0]
        for clause in all_clauses[1:]:
            result += f"; {clause}"
        return result + "."

